NEWS HEADLINE: \${json.headline}
NEWS SUMMARY: \${json.summary}

` + (images.length > 0 ? "Reference photos provided — use the actual person's likeness." : "") + (logob64 ? ` Logo image provided — incorporate the ${subjectName} logo naturally in the scene where it would realistically appear.` : "")
    }
