// Robustly extract the WaveSpeed generated image URL from multiple possible response shapes
const resp = $input.item.json;

const url =
  resp?.data?.outputs?.[0] ||
  resp?.outputs?.[0] ||
  resp?.data?.images?.[0] ||
  resp?.images?.[0] ||
  resp?.data?.url ||
  resp?.url ||
  resp?.data?.result ||
  resp?.result;

if (!url || typeof url !== 'string' || !url.startsWith('http')) {
  const raw = JSON.stringify(resp).slice(0, 500);
  throw new Error(`[WaveSpeed] Could not extract image URL from response. Tried data.outputs[0], outputs[0], data.images[0], images[0], data.url, url. Raw response: ${raw}`);
}

return [{ json: { ...$input.item.json, wavespeed_image_url: url } }];

const items = $input.all();
if (items.length === 0) return [];

// --- ROBUST FILTER: Only process items manually marked as "✅ Approved" ---
const approved = items.filter(item => {
  const status = item.json['Status'] || '';
  return status.includes('✅ Approved') || status === '✅ Approved';
});

if (approved.length === 0) {
  console.log('No approved items found in this batch.');
  return [];
}

// Sort by Engagement Score descending
const sorted = approved.sort((a, b) => (parseInt(b.json['Engagement Score']) || 0) - (parseInt(a.json['Engagement Score']) || 0));

// Pick the top one for processing
const selected = sorted.slice(0, 1);

// Map headers to internal briefing keys for compatibility
return selected.map(item => ({
  json: {
    row_number: item.json.row_number,
    title: item.json['Title'],
    text: item.json['Body'],
    author: item.json['Author'],
    original_score: item.json['Upvotes'],
    source_url: item.json['Article Link'] || item.json['URL'],
    reddit_url: item.json['Reddit Link'],
    subreddit: item.json['Subreddit'],
    date: item.json['Date'],
    status: item.json['Status']
  }
}));

const tavilyLogoResult = $input.item.json;
const rawImages = (tavilyLogoResult.images || []);
const existingData = $('Merge Image Data').item.json;

const companyDomain = existingData.company_domain || '';
const subjectName   = existingData.subject_name || '';

const validLogos = rawImages.filter(url =>
  typeof url === 'string' && url.length > 12 &&
  /\.(png|jpg|jpeg)(\?|$)/i.test(url) &&
  !/favicon|\.ico|sprite|placeholder/i.test(url)
);

let logo_base64 = null;
let logo_url    = null;

async function downloadImage(url, minSize) {
  try {
    const res = await fetch(url, { signal: AbortSignal.timeout(8000) });
    if (!res.ok) return null;
    const buf = Buffer.from(await res.arrayBuffer());
    const isPng  = buf[0]===0x89 && buf[1]===0x50;
    const isJpeg = buf[0]===0xFF && buf[1]===0xD8;
    if (buf.length >= (minSize || 200) && (isPng || isJpeg)) return buf;
  } catch(e) {}
  return null;
}

if (companyDomain) {
  // Strategy 1: Clearbit — no key, no signup, high quality PNG logos
  let buf = await downloadImage(`https://logo.clearbit.com/${companyDomain}?size=256`, 200);
  if (buf) { logo_base64 = buf.toString('base64'); logo_url = `clearbit:${companyDomain}`; }

  // Strategy 2: Google Favicon at 256px — no key, always works
  if (!logo_base64) {
    buf = await downloadImage(`https://www.google.com/s2/favicons?domain=${companyDomain}&sz=256`, 100);
    if (buf) { logo_base64 = buf.toString('base64'); logo_url = `google:${companyDomain}`; }
  }

  // Strategy 3: DuckDuckGo icon service — no key, no signup
  if (!logo_base64) {
    buf = await downloadImage(`https://icons.duckduckgo.com/ip3/${companyDomain}.ico`, 100);
    if (buf) { logo_base64 = buf.toString('base64'); logo_url = `ddg:${companyDomain}`; }
  }
}

// Strategy 4: Tavily image results fallback
if (!logo_base64) {
  for (const url of validLogos.slice(0, 5)) {
    const buf = await downloadImage(url, 500);
    if (buf) { logo_base64 = buf.toString('base64'); logo_url = url; break; }
  }
}

return [{
  json: {
    ...existingData,
    logo_base64,
    logo_url,
    subject_type:   existingData.subject_type || 'company',
    subject_name:   subjectName,
    company_domain: companyDomain
  }
}];
